import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Agent-First Documentation: A Case Study in Structuring a Codebase for AI-Assisted Development","description":"","frontmatter":{"docSection":"contributors","docType":"reference","audiences":["contributor"]},"headers":[],"relativePath":"agent-first-documentation.md","filePath":"agent-first-documentation.md"}'),o={name:"agent-first-documentation.md"};function i(r,e,d,l,c,h){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="agent-first-documentation-a-case-study-in-structuring-a-codebase-for-ai-assisted-development" tabindex="-1">Agent-First Documentation: A Case Study in Structuring a Codebase for AI-Assisted Development <a class="header-anchor" href="#agent-first-documentation-a-case-study-in-structuring-a-codebase-for-ai-assisted-development" aria-label="Permalink to &quot;Agent-First Documentation: A Case Study in Structuring a Codebase for AI-Assisted Development&quot;">​</a></h1><p>Most software projects accumulate documentation for humans. It is written in long-form prose, organised chronologically, and navigated with Cmd+F. When AI coding agents arrived, we handed them those same documents — and wondered why they kept losing context, re-reading irrelevant history, and drifting off course mid-task.</p><p>This is a case study of restructuring the documentation for <a href="https://github.com/sovereignfs/sovereign" target="_blank" rel="noreferrer">Sovereign</a> — a modular, self-hostable workspace runtime — to work agent-first. The goal was not to make documentation worse for humans, but to make it measurably better for agents without sacrificing human readability. We measured the results at each stage.</p><hr><h2 id="the-problem-documentation-shaped-for-humans-used-by-agents" tabindex="-1">The problem: documentation shaped for humans, used by agents <a class="header-anchor" href="#the-problem-documentation-shaped-for-humans-used-by-agents" aria-label="Permalink to &quot;The problem: documentation shaped for humans, used by agents&quot;">​</a></h2><p>Sovereign&#39;s working state was captured in two files:</p><ul><li><strong><code>CLAUDE.md</code></strong> (~400 lines) — conventions, architectural rules, active task pointer</li><li><strong><code>docs/roadmap.md</code></strong> (~2,400 lines) — every task in the project, in chronological phase order, each with a full prose entry: Goal, Deliverables, SRS reference, Review checklist</li></ul><p>The roadmap was the single source of truth. To start a task, an agent read it cover to cover. To check the review checklist mid-task, it read it again. To find related work in a domain, it scanned the full 2,400 lines looking for scattered mentions. The document was well-structured for a human reading it once — it was expensive for an agent reading it ten times a session.</p><p>Measuring the cost is straightforward. At roughly 15 tokens per line:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Lines read</th><th>Approximate tokens</th></tr></thead><tbody><tr><td>Session start — orient and find next task</td><td>~2,800</td><td>~42,000</td></tr><tr><td>Mid-task context refresh (&quot;what&#39;s my checklist?&quot;)</td><td>~2,400</td><td>~36,000</td></tr><tr><td>Domain overview (&quot;what are all the auth tasks?&quot;)</td><td>~2,400</td><td>~36,000</td></tr></tbody></table><p>Every agent session started with a ~42,000-token orientation pass. At Claude Sonnet input pricing that is roughly $0.13 per session start. More importantly, those 42,000 tokens filled the context window with phases, tasks, and domains that had nothing to do with the current work.</p><hr><h2 id="refactor-1-domain-first-epics-a-compact-roadmap" tabindex="-1">Refactor 1: domain-first epics + a compact roadmap <a class="header-anchor" href="#refactor-1-domain-first-epics-a-compact-roadmap" aria-label="Permalink to &quot;Refactor 1: domain-first epics + a compact roadmap&quot;">​</a></h2><p>The first structural change introduced a layer between the roadmap and the task detail.</p><h3 id="what-we-built" tabindex="-1">What we built <a class="header-anchor" href="#what-we-built" aria-label="Permalink to &quot;What we built&quot;">​</a></h3><p><strong>16 domain epic files</strong> in <code>docs/epics/</code>, each collecting all tasks for a domain regardless of when they shipped. Infrastructure, Users &amp; Auth, Platform Shell, Plugins Runtime, Theming, and so on. Each epic file contains full task entries — Goal, Deliverables, SRS reference, Review checklist — using a stable task ID scheme (<code>&lt;epic&gt;.&lt;seq&gt;</code>) independent of roadmap version numbers.</p><p><strong>A compact roadmap</strong> reduced to a version-indexed table: one row per PR, with a link to the canonical task entry in the relevant epic file. 139 lines instead of 2,412.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLAUDE.md                  ← session entry point; conventions</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─▶ docs/roadmap.md    ← 139-line chronological index</span></span>
<span class="line"><span>            │</span></span>
<span class="line"><span>            └─▶ docs/epics/&lt;epic&gt;.md   ← full task detail, loaded on demand</span></span></code></pre></div><p>The key insight is that agents — like humans — should only load what they need. An agent working on email templates does not need to read about monorepo scaffolding, Postgres validation, and the icon system first.</p><h3 id="the-current-task-md-mechanism" tabindex="-1">The <code>CURRENT_TASK.md</code> mechanism <a class="header-anchor" href="#the-current-task-md-mechanism" aria-label="Permalink to &quot;The \`CURRENT_TASK.md\` mechanism&quot;">​</a></h3><p>Domain-grouping helps with planning and orientation, but it still requires a navigation hop: roadmap → find epic → read task block. For the most frequent operation — &quot;what am I building right now?&quot; — we added <code>CURRENT_TASK.md</code>: a transient file written to the repo root by the <code>/sv-task-start</code> skill and deleted by <code>/sv-task-complete</code>.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Current Task</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Epic task:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 9.9</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Roadmap version:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 0.9.1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Branch:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> feat/email-templates</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Epic file:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> docs/epics/design-system.md</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">#### ⏳ 9.9 — Email template system + White-labeling Phase 2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Goal:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Deliverables:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Review checklist:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span></code></pre></div><p>Any agent or sub-agent working on the current task reads this one file. No roadmap scan. No epic navigation. The full spec, assembled once at task-start, available instantly for the rest of the session.</p><h3 id="measured-results-after-refactor-1" tabindex="-1">Measured results after Refactor 1 <a class="header-anchor" href="#measured-results-after-refactor-1" aria-label="Permalink to &quot;Measured results after Refactor 1&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Before</th><th>After</th><th>Reduction</th></tr></thead><tbody><tr><td>Session start (CURRENT_TASK.md exists)</td><td>~42,000 tokens</td><td>~7,000 tokens</td><td><strong>84%</strong></td></tr><tr><td>Session start (fresh, no CURRENT_TASK.md)</td><td>~42,000 tokens</td><td>~9,300 tokens</td><td><strong>78%</strong></td></tr><tr><td>Mid-task context refresh</td><td>~36,000 tokens</td><td>~750 tokens</td><td><strong>98%</strong></td></tr><tr><td>Domain overview</td><td>~36,000 tokens</td><td>~5,500 tokens</td><td><strong>85%</strong></td></tr><tr><td>Task completion writes</td><td>3 writes (complex)</td><td>2 writes + delete</td><td><strong>1 fewer</strong></td></tr><tr><td>Total documentation corpus</td><td>~2,900 lines</td><td>~3,600 lines</td><td>+24% (by design)</td></tr></tbody></table><p>The corpus grew because all the task prose that lived in the roadmap now lives in epic files. That is intentional — it is loaded on demand rather than all at once. The 24% growth is the cost of the structure.</p><p>The 98% reduction on mid-task refreshes is striking. It happens because <code>CURRENT_TASK.md</code> is purpose-built for that use case — 50 lines of exactly what the agent needs, nothing else.</p><hr><h2 id="refactor-2-role-based-agents-for-the-task-lifecycle" tabindex="-1">Refactor 2: role-based agents for the task lifecycle <a class="header-anchor" href="#refactor-2-role-based-agents-for-the-task-lifecycle" aria-label="Permalink to &quot;Refactor 2: role-based agents for the task lifecycle&quot;">​</a></h2><p>The workflow refactor addressed context load. The second change addressed context <em>quality</em> — specifically, what the main implementation agent has to process that it should not.</p><h3 id="the-problem-with-a-monolithic-task-complete-flow" tabindex="-1">The problem with a monolithic task-complete flow <a class="header-anchor" href="#the-problem-with-a-monolithic-task-complete-flow" aria-label="Permalink to &quot;The problem with a monolithic task-complete flow&quot;">​</a></h3><p>After implementation, the current agent ran the full check suite, processed the output, updated two documentation files, bumped versions, and drafted the PR description — sequentially, in the same context window. Raw typecheck output (98 lines in this project, hundreds in larger ones) sat in context while the agent tried to write a coherent PR description. Documentation updates context-switched the agent away from the implementation it was about to summarise.</p><h3 id="focused-role-agents" tabindex="-1">Focused role agents <a class="header-anchor" href="#focused-role-agents" aria-label="Permalink to &quot;Focused role agents&quot;">​</a></h3><p>The workflow uses focused skill files, each a standalone agent brief:</p><p><strong><code>/sv-verify</code></strong> — reads <code>CURRENT_TASK.md</code>, runs <code>format:check</code>, <code>lint</code>, <code>typecheck</code>, <code>test</code>, <code>build</code>, and optionally docs-parity. Returns a structured pass/fail table, not raw output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| Check        | Result   | Notes              |</span></span>
<span class="line"><span>|--------------|----------|--------------------|</span></span>
<span class="line"><span>| format:check | ✅ PASS  | —                  |</span></span>
<span class="line"><span>| lint         | ✅ PASS  | —                  |</span></span>
<span class="line"><span>| typecheck    | ✅ PASS  | —                  |</span></span>
<span class="line"><span>| test         | ✅ PASS  | 47 tests passed    |</span></span>
<span class="line"><span>| build        | ✅ PASS  | —                  |</span></span></code></pre></div><p><strong><code>/sv-update-task-docs</code></strong> — reads <code>CURRENT_TASK.md</code> for metadata, marks the roadmap row ✅, updates the matching epic task heading ✅, and deletes <code>CURRENT_TASK.md</code>.</p><p><strong><code>/sv-security-check</code></strong> — conditional on the diff touching sensitive paths (auth, middleware, CSP, cookies, SDK surface). Reviews the diff against a lookup table of hard architectural rules: redirect codes, CSP construction, cookie clearing patterns, session config invariants. Violations block the PR draft.</p><p><strong><code>/sv-create-pr</code></strong> — creates the GitHub pull request as a draft with <code>gh pr create --draft</code> when the developer asks for a PR. Ready-for-review remains an explicit human action.</p><h3 id="the-parallel-execution-model" tabindex="-1">The parallel execution model <a class="header-anchor" href="#the-parallel-execution-model" aria-label="Permalink to &quot;The parallel execution model&quot;">​</a></h3><p><code>/sv-task-complete</code> now spawns Verifier and Docs Updater simultaneously, then conditionally runs the Security Check, then hands the main agent a clean result to work from:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[parallel]</span></span>
<span class="line"><span>  /sv-verify       — checks pass/fail (30–60s)</span></span>
<span class="line"><span>  /sv-update-task-docs— roadmap + epic heading + cleanup (5–10s)</span></span>
<span class="line"><span>[sequential]</span></span>
<span class="line"><span>  /sv-security-check— only if diff touches sensitive paths</span></span>
<span class="line"><span>  main agent       — version bumps + PR description</span></span>
<span class="line"><span>  /sv-create-pr    — draft PR when requested</span></span></code></pre></div><p>Each role agent is briefed with <code>CURRENT_TASK.md</code> (~50 lines) plus its skill file. It needs nothing else. Before this refactor, a sub-agent needed a full project orientation pass to know what it was reviewing.</p><h3 id="measured-results-after-role-agents" tabindex="-1">Measured results after role agents <a class="header-anchor" href="#measured-results-after-role-agents" aria-label="Permalink to &quot;Measured results after role agents&quot;">​</a></h3><p>The token savings from role agents are modest as a fraction of overall session cost — because the implementation phase dominates and no role agent touches it:</p><table tabindex="0"><thead><tr><th>Phase</th><th>After Refactor 1</th><th>After role agents</th><th>Reduction</th></tr></thead><tbody><tr><td>Session start</td><td>~7,000 tokens</td><td>~7,000 tokens</td><td>No change</td></tr><tr><td>Implementation</td><td>~30,000–50,000</td><td>~30,000–50,000</td><td>No change</td></tr><tr><td>Task-complete phase</td><td>~4,500 tokens</td><td>~1,050 tokens</td><td><strong>77%</strong></td></tr><tr><td><strong>Full session</strong></td><td>~42,000–62,000</td><td>~38,000–58,000</td><td><strong>~7%</strong></td></tr></tbody></table><p>The honest headline number is 7% per-session token reduction. That undersells the actual value for two reasons.</p><p><strong>Context cleanliness.</strong> The main agent drafts the PR description without 119 lines of typecheck output in its context window. Noise influences generation quality in ways that are real but hard to quantify — the output from a clean-context PR draft is observably better than one written after processing a wall of compiler output.</p><p><strong>Wall-clock parallelism.</strong> Verification takes ~30–60 seconds; the docs update takes ~10 seconds. Running them in parallel saves roughly the docs-update time per task completion — ~10–15 seconds, or about 20% of the complete-phase wall-clock.</p><p><strong>Security coverage.</strong> This is a new capability, not an optimisation of an existing one. Before: no automatic security review. After: every PR touching auth/middleware/CSP gets a targeted diff review against a concrete rules checklist. If it catches one issue per ten tasks that would otherwise require a fix PR, it eliminates a full task cycle worth of work every ten tasks — which exceeds all the token savings above.</p><hr><h2 id="combined-gains-the-full-picture" tabindex="-1">Combined gains: the full picture <a class="header-anchor" href="#combined-gains-the-full-picture" aria-label="Permalink to &quot;Combined gains: the full picture&quot;">​</a></h2><p>Stacking both refactors across a full task session:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Baseline</th><th>After Refactor 1</th><th>After role agents</th></tr></thead><tbody><tr><td>Session start tokens</td><td>~42,000</td><td>~7,000</td><td>~7,000</td></tr><tr><td>Mid-task refresh</td><td>~36,000 tokens</td><td>~750 tokens</td><td>~750 tokens</td></tr><tr><td>Task-complete context</td><td>~4,500 tokens</td><td>~4,500 tokens</td><td>~1,050 tokens</td></tr><tr><td>Full session tokens</td><td>~80,000+</td><td>~42,000–62,000</td><td>~38,000–58,000</td></tr><tr><td>Security coverage</td><td>Manual</td><td>Manual</td><td>Automatic</td></tr><tr><td>Maintenance touch points</td><td>3 writes</td><td>3 writes</td><td>2 writes + delete</td></tr></tbody></table><p>The refactors are complementary: Refactor 1 addressed session-start cost (the most frequent operation), role agents addressed completion-phase cost and added a capability.</p><hr><h2 id="principles-worth-keeping" tabindex="-1">Principles worth keeping <a class="header-anchor" href="#principles-worth-keeping" aria-label="Permalink to &quot;Principles worth keeping&quot;">​</a></h2><p>Working through this, a few principles emerged that feel applicable beyond this specific project:</p><p><strong>Load context on demand, not upfront.</strong> The biggest gain came from not loading the entire roadmap to answer &quot;what do I do next?&quot; The human assigns the task, and <code>CURRENT_TASK.md</code> holds the current-task detail — so an agent loads the relevant task context instead of the whole roadmap to orient itself.</p><p><strong>Separate chronological index from canonical spec.</strong> The roadmap is now a version-ordered index that points to epic files. The epic files are the spec. These are different concerns with different consumers: the roadmap answers &quot;when did this ship?&quot;, the epic answers &quot;what exactly does this task entail?&quot; Conflating them made both worse.</p><p><strong>Stable cross-references beat fragile anchors.</strong> We replaced markdown anchor links (<code>#313--per-plugin-database</code>) with plain epic task IDs (<code>[3.13]</code>). Anchor links silently break when a heading is renamed; task IDs are stable forever.</p><p><strong>Role agents need tight briefs, not full context.</strong> The Security Check agent only needs <code>CURRENT_TASK.md</code> plus the rules table — not the full CLAUDE.md, not the roadmap, not the epic files. Designing role agents with minimal brief surfaces forces clarity about what each role actually needs to know.</p><p><strong>Measure before claiming wins.</strong> The &quot;role agents save tokens&quot; story looked compelling until we measured: 7% of overall session cost. The real wins were context cleanliness and security coverage, not tokens. Measuring surfaced the honest picture and avoided over-investing in marginal gains.</p><hr><h2 id="what-we-did-not-do" tabindex="-1">What we did not do <a class="header-anchor" href="#what-we-did-not-do" aria-label="Permalink to &quot;What we did not do&quot;">​</a></h2><p><strong>We did not create a machine-readable task manifest.</strong> A <code>tasks.json</code> would be faster for agents to query than grep-searching markdown files. It remains a possible future improvement, but the current markdown-based approach has a meaningful advantage: humans and agents read the same files, so there is no synchronisation problem between a &quot;human-facing&quot; doc and a &quot;machine-facing&quot; manifest.</p><p><strong>We did not add role agents to the implementation phase.</strong> Multiple agents writing to the same codebase simultaneously creates coordination problems that cost more than they save. The implementation phase remains a single focused agent. Role agents live at the edges: task start, task complete, security review.</p><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>The structural refactor reduced session-start context load by 84% and mid-task refresh cost by 98%. Role agents parallelised the task-complete phase and added automatic security coverage. The total documentation corpus grew 24% — but that growth is now spread across files that agents load selectively, rather than concentrated in a single file that agents must scan in full.</p><p>More broadly, the exercise confirmed that documentation architecture matters for agentic workflows in the same way that API design matters for software systems: a well-designed interface means consumers only pay for what they use. The roadmap was a useful human document and a costly agent interface. Separating the two concerns — a compact index for navigation, rich spec files loaded on demand — made it a better interface for both.</p><p>The full implementation lives in the Sovereign repository. The key files are:</p><ul><li><a href="https://github.com/sovereignfs/sovereign/tree/main/docs/epics" target="_blank" rel="noreferrer"><code>docs/epics/</code></a> — 16 domain epic files with full task detail</li><li><a href="https://github.com/sovereignfs/sovereign/blob/main/docs/roadmap.md" target="_blank" rel="noreferrer"><code>docs/roadmap.md</code></a> — 139-line version-indexed table</li><li><a href="./development-workflow.html"><code>docs/development-workflow.md</code></a> — workflow reference for agents and contributors</li><li><a href="https://github.com/sovereignfs/sovereign/tree/main/.claude/commands" target="_blank" rel="noreferrer"><code>.claude/commands/</code></a> and <a href="https://github.com/sovereignfs/sovereign/tree/main/.agents/skills" target="_blank" rel="noreferrer"><code>.agents/skills/</code></a> — task lifecycle commands and skills</li></ul><hr><p>Co-authored by Claude Code + Codex with humans.</p><p>Created: 2026-06-23</p><p>Last updated: 2026-06-30</p>`,77)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
